import{_ as a,o as t,c as r,ag as s}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/1.B7pwWZre.jpg",i="/kaiping-reports/assets/2.Do8CzNQI.jpg",p="/kaiping-reports/assets/3.DsycNTtV.jpg",n="/kaiping-reports/assets/4.DTXCsD82.jpg",m="/kaiping-reports/assets/5.SPUKK085.jpg",l="/kaiping-reports/assets/6.CwoAmjzK.jpg",h="/kaiping-reports/assets/7.2_jPNDHp.jpg",g="/kaiping-reports/assets/8.Bp2BS6zt.jpg",c="/kaiping-reports/assets/9.I0ZneSUB.jpg",d="/kaiping-reports/assets/10.CU6KtXOI.jpg",j=JSON.parse('{"title":"开平近代建筑装饰符号与文化表达调研报告","description":"","frontmatter":{"title":"开平近代建筑装饰符号与文化表达调研报告"},"headers":[],"relativePath":"reports/梁浩然/梁浩然_调研报告.md","filePath":"reports/梁浩然/梁浩然_调研报告.md"}'),_={name:"reports/梁浩然/梁浩然_调研报告.md"};function u(b,e,q,f,k,P){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="开平近代建筑装饰符号与文化表达调研报告" tabindex="-1">开平近代建筑装饰符号与文化表达调研报告 <a class="header-anchor" href="#开平近代建筑装饰符号与文化表达调研报告" aria-label="Permalink to &quot;开平近代建筑装饰符号与文化表达调研报告&quot;">​</a></h1><h2 id="开平近代建筑装饰符号与文化表达调研报告-1" tabindex="-1"><em><strong>/<em>开平近代建筑装饰符号与文化表达调研报告/</em></strong></em> <a class="header-anchor" href="#开平近代建筑装饰符号与文化表达调研报告-1" aria-label="Permalink to &quot;***/*开平近代建筑装饰符号与文化表达调研报告/****&quot;">​</a></h2><h3 id="——以立园、仓东村、塘口墟、赤坎古镇为例" tabindex="-1"><strong><em>/</em>——以立园、仓东村、塘口墟、赤坎古镇为例/</strong>** <a class="header-anchor" href="#——以立园、仓东村、塘口墟、赤坎古镇为例" aria-label="Permalink to &quot;***/*——以立园、仓东村、塘口墟、赤坎古镇为例/****&quot;">​</a></h3><p>考察地点： 广东省江门市开平市</p><p>考察时间： 2026年3月31日</p><p>考察小组： 梁浩然</p><p>指导教师： 石托</p><p>开平近代建筑的装饰并非附着于结构表面的“多余形式”，而是侨乡社会文化身份、跨国经验与地方审美共同作用的结果。无论是碉楼、居庐、园林还是骑楼街，其装饰系统都表现出鲜明的“中西并置”与“地方再诠释”特征：西方柱式、拱券、山花、穹窿、彩色玻璃等形式，被嵌入岭南灰塑、书法匾额、吉祥纹样和宗族礼制空间之中，构成一种既不完全西化、也不回到纯传统的文化表达。本文以立园、仓东村、塘口墟、赤坎古镇四处案例为基础，分析其装饰位置、题材来源、色彩组织与意义转化，说明开平建筑装饰的核心不在“拼贴”，而在于对华侨身份、现代性想象和地方认同的可视化建构。</p><p>开平；建筑装饰；文化表达；中西合璧；侨乡；赤坎骑楼；立园；仓东村</p><h3 id="一、问题意识与观察路径" tabindex="-1"><em><strong>/<em>一、问题意识与观察路径/</em></strong></em> <a class="header-anchor" href="#一、问题意识与观察路径" aria-label="Permalink to &quot;***/*一、问题意识与观察路径/****&quot;">​</a></h3><p>方案书将维度三界定为“中西融合特征、雕刻题材、色彩运用”，并要求对装饰位置、题材和风格进行分类记录。这一要求非常适合开平，因为开平建筑最突出的艺术特征，恰恰不是单一的形式来源，而是来自多重文化的视觉叠合。已有研究表明，20世纪二三十年代的五邑侨乡建筑普遍“以模仿西洋建筑为尚”，但这种模仿并非原样复制，而是经由本地匠人和地方社会重新组织，最终形成具有侨乡特征的混合风格。</p><h3 id="二、立园-园林叙事中的身份装饰" tabindex="-1"><em><strong>/<em>二、立园：园林叙事中的身份装饰/</em></strong></em> <a class="header-anchor" href="#二、立园-园林叙事中的身份装饰" aria-label="Permalink to &quot;***/*二、立园：园林叙事中的身份装饰/****&quot;">​</a></h3><p>立园是分析装饰符号最典型的样本之一。官方资料明确指出，立园建筑以中西合璧为主，主要建筑为钢筋混凝土结构，同时保留壁画、灰塑等装饰；大牌坊上“立园”二字为吴道镕题写，柱身使用水刷石，檐口采用暗红色水泥斗拱等仿木装饰。由此可见，立园装饰的第一层意义并不是“豪华”，而是将华侨阶层的文化资本、书写传统和现代技术整合成一种可被观看的家园形象。</p><p><img src="'+o+'" alt="图1：立园"></p><p>立园的装饰系统至少包含四个层面：其一，柱式装饰明显吸收古典西方建筑语汇，尤其在柱头处理上更接近科林斯式或复合式倾向；其二，室内壁画、家具、框景和窗扇共同强化了居住空间的“展厅化”；其三，书法匾额与中式题名将园林叙事重新拉回中国传统文脉；其四，整体色彩以浅黄色、米白、水泥灰、深木色和局部暗红为主，形成一种兼具洋楼优雅与岭南温润的综合色调。这里的西式柱式并未破坏中国园林秩序，反而被纳入“门楼—庭院—别墅—景窗”这一东方空间组织中，装饰因此成为文化调和的媒介。</p><p><img src="'+i+'" alt="图2：立泮"></p><p>更重要的是，立园装饰不是孤立的外立面秀场，而是与华侨身份叙事相互支撑。西方柱式、别墅轮廓和室内陈设象征主人曾经接触过的海外现代生活；书法匾额、园林轴线和仿古牌坊则确保这种现代性仍被纳入中国家族伦理与地方文化之中。也就是说，立园的装饰不是“西方化”的证明，而是“已经见过世界之后仍要回到故乡”的可视表达。</p><h3 id="三、仓东村-宗族空间中的混合装饰" tabindex="-1"><em><strong>/<em>三、仓东村：宗族空间中的混合装饰/</em></strong></em> <a class="header-anchor" href="#三、仓东村-宗族空间中的混合装饰" aria-label="Permalink to &quot;***/*三、仓东村：宗族空间中的混合装饰/****&quot;">​</a></h3><p>仓东村的装饰更接近“日常生活中的文化混合”。相关研究与仓东村项目资料表明，仓东村是典型侨乡聚落，海外汇款促成住宅、祠堂、学校等设施建设，而“仓东计划”则把建筑修复、社区营造和非遗保护结合起来。五邑大学关于仓东展示馆的介绍进一步指出，秉文谢公祠内集中展示了木雕、灰雕、砖雕、石雕、壁画等本土工艺，这恰好说明仓东村装饰的核心并不只是西式样式，而是地方工艺如何承载侨乡文化记忆。</p><p><img src="'+p+'" alt="图3：仓东村祠堂"></p><p>从色彩与位置看，仓东村装饰通常不追求立园那样的完整华丽，而更强调礼制节点的突出：祠堂正立面、额枋、梁架、檐口与门楣是装饰最集中的区域；民居则相对朴素，通过少量灰塑、窗饰和局部图案提升建筑辨识度。这样的分配方式，说明装饰在仓东村首先服务于宗族空间等级，而不是单纯追求外观炫耀。换言之，仓东村建筑装饰的文化表达带有更强的“共同体属性”。</p><p><img src="'+n+'" alt="图4：仓东村建筑外观"></p><p><img src="'+m+'" alt="图5：仓东村碉楼外观"></p><h3 id="四、塘口墟-从实用工业语汇到新文化符号" tabindex="-1"><em><strong>/<em>四、塘口墟：从实用工业语汇到新文化符号/</em></strong></em> <a class="header-anchor" href="#四、塘口墟-从实用工业语汇到新文化符号" aria-label="Permalink to &quot;***/*四、塘口墟：从实用工业语汇到新文化符号/****&quot;">​</a></h3><p>塘口墟它的价值并不主要来自传统繁复装饰，而来自装饰意义的转换。先锋天下粮仓书店原为20世纪70年代粮仓群，官方介绍把其改造阐释为以“精神食粮”再现“天下粮仓”风采。也就是说，这一案例的文化表达首先发生在符号层面：储粮设施被重新命名为书店，农业基础设施转化为文化消费空间，原本极度实用的工业形象获得了新的公共意义。</p><p>先锋天下粮仓及周边旧墟街区的视觉表达呈现出一种“克制的装饰性”。其仓体轮廓、黑色屋顶、白色墙身和成组排列本身就是最强的形式语言。</p><p><img src="'+l+'" alt="图6：先锋天下粮仓外观"></p><p>与其说这里以雕刻和纹样取胜，不如说它通过保留旧仓轮廓、工业尺度和场地记忆，形成一种去繁饰化的当代审美。与此同时，塘口墟周边侨乡建筑仍保留罗马柱、巴洛克屋顶等混合语汇，官方与媒体材料也多次将塘口建筑概括为“不同建筑语言相互交融”。因此，塘口墟的文化表达实际上发生在两层：一层是旧侨乡建筑固有的中西混合装饰，一层是当代更新项目对“乡村创意共同体”形象的再生产。</p><p>这意味着，塘口墟今天最重要的“装饰”已经不只是门楣、柱式和纹样，而是由建筑命名、场所叙事、空间展示和视觉品牌共同构成的符号系统。</p><h3 id="五、赤坎古镇-骑楼街区中的-世界建筑语汇" tabindex="-1"><em><strong>/<em>五、赤坎古镇：骑楼街区中的“世界建筑语汇”/</em></strong></em> <a class="header-anchor" href="#五、赤坎古镇-骑楼街区中的-世界建筑语汇" aria-label="Permalink to &quot;***/*五、赤坎古镇：骑楼街区中的“世界建筑语汇”/****&quot;">​</a></h3><p><img src="'+h+'" alt="图7：赤坎古镇水景"></p><p>赤坎古镇是开平装饰符号最密集、最具街区戏剧性的地点之一。官方介绍明确指出，赤坎骑楼中可见古罗马柱式、哥特式尖塔、巴洛克风格屋顶和彩色玻璃门窗；另有材料称，其骑楼街仿佛“世界建筑博物馆”，古希腊柱廊、古罗马穹窿、葡萄牙骑楼、岭南佳果与吉祥纹饰、中国古典卷草图案并存。对比立园的园林式整合，赤坎更像是把海外见闻直接投射到商业街立面上，从而形成一条高度视觉化的侨乡商业展示界面。</p><p><img src="'+g+'" alt="图8：赤坎古镇骑楼街区"></p><p>如果以“赤坎骑楼街区”为例，其装饰语言至少包括柱式、拱券、山花、栏杆、门窗和彩色材料六个层面。柱式决定了底层骑楼的公共性和节奏感；拱券与山花强化了西式街景印象；金属栏杆与窗扇则增加了楼上生活界面的细节密度；而岭南灰塑、吉祥纹饰和中文招牌又不断把这种“洋味”拉回本地生活世界。赤坎骑楼最有意思的地方正是在这里：它不是一组彼此孤立的漂亮楼房，而是一条商业街如何通过连续而多变的装饰立面，把侨汇资本、南洋经验、岭南工艺和中国市镇日常共同转译成可消费、可识别、可记忆的公共图像。</p><p><img src="'+c+'" alt="图9：赤坎古镇水景"></p><p>在色彩方面，赤坎的装饰并不依赖高饱和度，而更依赖抹灰墙面的旧黄、灰白、水泥色、深色窗框与历史招牌共同塑造时间感。也因此，赤坎的文化表达具有鲜明的“街区性”而非“单体性”：单栋建筑即使装饰丰富，也必须在连续街景中才真正成立。对于维度三而言，赤坎最重要的观察不是“这栋楼用了什么柱子”，而是“为什么这条街需要如此多元却又协调的装饰语言”。答案就在于，它承担的是侨乡商业中心的门面功能，是一个地方社会向内组织日常、向外展示现代性的视觉舞台。<img src="'+d+'" alt="图10：赤坎古镇水景"></p><h3 id="六、比较结论-装饰如何成为侨乡社会的可视叙事" tabindex="-1"><em><strong>/<em>六、比较结论：装饰如何成为侨乡社会的可视叙事/</em></strong></em> <a class="header-anchor" href="#六、比较结论-装饰如何成为侨乡社会的可视叙事" aria-label="Permalink to &quot;***/*六、比较结论：装饰如何成为侨乡社会的可视叙事/****&quot;">​</a></h3><p>综合四个案例可见，开平近代建筑装饰并非简单分成“中式”与“西式”两栏，而是可归纳为三种不同的文化表达机制。第一，立园属于“身份型装饰”，强调个人/家族的文化资本与审美教养；第二，仓东村属于“共同体型装饰”，强调宗族礼制、地方工艺和乡村教育；第三，塘口墟与赤坎古镇则更接近“公共传播型装饰”，前者依靠更新叙事与视觉品牌重塑旧墟，后者依靠连续骑楼街景把侨乡商业文明具象化。四者虽形式不同，但都证明了一个事实：开平建筑装饰从来不是纯形式问题，而是社会关系、跨国经验与地方精神的视觉沉积。</p><p>因此，维度三的调研最终不应停留在“哪里有罗马柱、哪里有灰塑”的罗列，而应进一步追问：为何这些符号会在侨乡出现，谁选择了它们，它们被安放在什么空间位置，又向谁传达何种信息。只有把装饰放回侨乡社会史、建筑史与地方文化之中，开平近代建筑“中西合璧”的真正含义才会显现出来。</p><h3 id="七-、附录-调研记录" tabindex="-1"><em><strong>/<em>七/</em></strong></em><strong><em>/</em>、附录：调研记录/</strong>** <a class="header-anchor" href="#七-、附录-调研记录" aria-label="Permalink to &quot;***/*七/*******/*、附录：调研记录/****&quot;">​</a></h3><h3 id="_7-1-摄影记录" tabindex="-1"><em><strong>/<em>7/</em></strong></em><strong><em>/</em>.1 摄影记录/</strong>** <a class="header-anchor" href="#_7-1-摄影记录" aria-label="Permalink to &quot;***/*7/*******/*.1 摄影记录/****&quot;">​</a></h3><h3 id="本报告共插入10张现场照片-分别展示" tabindex="-1">本报告共插入10张现场照片，分别展示： <a class="header-anchor" href="#本报告共插入10张现场照片-分别展示" aria-label="Permalink to &quot;本报告共插入10张现场照片，分别展示：&quot;">​</a></h3><p>图1-图2：立园建筑外观</p><p>图3-图5：仓东村村落景观</p><p>图6：先锋天下粮仓书店</p><p>图7-图10：赤坎古镇骑楼街景与水田景观</p><h3 id="_7-2-参考文献" tabindex="-1"><em><strong>/<em>7/</em></strong></em><strong><em>/</em>.2/</strong>** <em><strong>/<em>参考文献/</em></strong></em> <a class="header-anchor" href="#_7-2-参考文献" aria-label="Permalink to &quot;***/*7/*******/*.2/**** ***/*参考文献/****&quot;">​</a></h3><ol><li>UNESCO World Heritage Centre. <em>Kaiping Diaolou and Villages</em>.</li><li>Batto, Patricia R. S. 2006. <em>The Diaolou of Kaiping (1842–1937): Buildings for Dangerous Times</em>. China Perspectives.</li><li>Tan, Selia Jinhua, and Zheng Dehua. 2012. <em>The Architectural Style and Cultural Connotation of Lu Mansions in Kaiping of Guangdong</em>. <em>Advanced Materials Research</em> 598: 12–21.</li><li>谭金花. 2013.《广东开平侨乡民国建筑装饰的特点与成因及其社会意义（1911—1949）》.《华南理工大学学报（社会科学版）》15(3): 54–60.</li><li>谭金花. 2015.《乡村文化遗产保育与发展的研究及实践探索——以广东开平仓东村为例》.《南方建筑》2015(1): 18–23.</li><li>谭金花. 2016.《碉楼与庐：五邑侨乡建筑风格的演变及文化根源》.《五邑大学学报（社会科学版）》18(1): 1–7.</li><li>斯坦福大学仓东村项目与五邑大学仓东相关资料。</li></ol><p>开平市、塘口镇、赤坎镇人民政府关于立园、塘口墟、赤坎骑楼的官方介绍。</p>',49)])])}const S=a(_,[["render",u]]);export{j as __pageData,S as default};
